// Import of required libraries
import { test } from '@playwright/test';
import { expect, newSkyrampPlaywrightPage } from '@skyramp/skyramp';

const pageTimeout = 15000;

test('testUi', async ({ page }) => {
    test.setTimeout(363000);

    // set default timeout for all locator/page actions in this test
    page.setDefaultTimeout(pageTimeout);
    // Wrap playwright page with Skyramp page
    page = newSkyrampPlaywrightPage(page);

    // Register page error listener BEFORE navigation to capture rendering errors
    const errors: string[] = [];
    page.on('pageerror', (err) => errors.push(err.message));

    await page.goto("http://localhost:5173");
    await page.goto("http://localhost:5173/orders");
    await page.waitForLoadState('networkidle');

    await page.getByTestId("order-def@mail.com - 2 items").getByRole("button", { name: "View details for order 1" }).click();
    await page.waitForLoadState('networkidle');
    await page.getByTestId("order-detail-edit-btn").click();
    await page.goto("http://localhost:5173/orders/1");
    await page.waitForLoadState('networkidle');
    await expect(page.getByTestId("order-detail-heading")).toContainText("Order Details");
    await page.getByTestId("order-detail-edit-btn").click();
    // Assert the edit form rendered after clicking Edit Order (fails if SelectItem crash occurs)
    await expect(page.getByTestId("order-detail-edit-form")).toBeVisible();
    // Assert no page errors were thrown during editing (catches the <Select.Item value=""> crash)
    expect(errors).toHaveLength(0);
});
